// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
   if (isLoading || newValue === '') {
      return;
   }
	// STRY0074671 - hide members
	if(g_form.getValue('u_external_flag') == 'true'){
		g_form.hideRelatedList('x_153465_discovert_discover_office_members');
	}else{
		g_form.showRelatedList('x_153465_discovert_discover_office_members');
	}
}
